INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$PDF Compression$q$, $q$Reduce PDF file size while aiming to preserve readable quality for easier sharing and emailing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$File Conversion$q$, $q$Convert PDFs to and from Word, Excel, PowerPoint, and JPG formats in either direction.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Merge and Split$q$, $q$Combine multiple PDFs into one document or split a single PDF into separate files by page range.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$E-Signature$q$, $q$Request, collect, and apply legally recognized electronic signatures directly on PDF documents.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$PDF Editing$q$, $q$Add text, images, shapes, and annotations to existing PDF pages in the browser.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Password Protection and Unlocking$q$, $q$Encrypt PDFs with a password or remove existing password protection from files you have rights to.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$AI Summarization and Translation$q$, $q$Generate quick document summaries and translate PDF content into other languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Batch Processing$q$, $q$Run the same task, such as compression or conversion, across many files at once on paid plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Cross-Platform Access$q$, $q$Use Smallpdf through a web browser, dedicated iOS and Android apps, or a desktop application.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Simple, single-purpose tools that require no learning curve for common PDF tasks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$No software installation needed for browser-based use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Broad multilingual interface supports an international user base$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Available across web, mobile, and desktop for flexible workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Free tier covers occasional, low-volume PDF needs at no cost$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Free plan imposes daily task limits that restrict frequent use$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Cloud-based processing means files are uploaded to Smallpdf's servers rather than processed locally$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Lacks the advanced editing and authoring depth of full desktop PDF suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Pro subscription is required for unlimited and batch usage, adding recurring cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Some AI features and labels may not be fully localized in every supported language$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Is Smallpdf free to use?$q$, $q$Yes, Smallpdf offers a free plan with basic tools, but it limits the number of tasks you can complete per day. Unlimited use requires a Pro or Team subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Does Smallpdf work on mobile devices?$q$, $q$Yes, Smallpdf provides native iOS and Android apps in addition to its web app, so files can be processed from a phone or tablet.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Can I use Smallpdf without creating an account?$q$, $q$Many core tools can be used without signing up, though creating a free account typically removes some restrictions and saves file history.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$What does a Smallpdf Pro subscription add?$q$, $q$Pro removes daily task limits, unlocks batch processing across multiple files, adds desktop app access, and removes ads from the experience.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Is Smallpdf secure for sensitive documents?$q$, $q$Smallpdf states it encrypts files in transit and deletes them from its servers after a period, but organizations with strict data-residency or on-premise requirements should review its cloud-processing model before relying on it for highly sensitive files.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Emailing large attachments$q$, $q$Compress oversized PDFs so they fit within email attachment limits without losing readability.$q$, $q$Office workers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Collecting contract signatures$q$, $q$Send a PDF contract for e-signature and track completion without printing or scanning.$q$, $q$Small business owners and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Converting scanned forms to editable text$q$, $q$Turn a scanned PDF form into an editable Word or Excel file for further updates.$q$, $q$Administrative staff and freelancers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Consolidating multi-part documents$q$, $q$Merge several separate PDFs, such as scanned receipts or chapters, into a single organized file.$q$, $q$Bookkeepers and researchers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Limited daily tasks","Core PDF tools","Web-based access","File size limits apply"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Pro$q$, $q$$9-15/month$q$, $q$Monthly or annual$q$, $q$["Unlimited tasks","All PDF tools","Batch processing","Desktop app access","No file size limits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Team$q$, $q$$7-12/user/month$q$, $q$Monthly or annual$q$, $q$["Everything in Pro","Centralized billing","Shared team access","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$Business$q$, $q$Custom$q$, $q$Contact sales$q$, $q$["Everything in Team","Advanced admin controls","SSO options","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Smallpdf is a Zurich-based online PDF platform launched in 2013 that grew out of a single compression tool into a suite of more than 20 utilities for handling documents. Its core promise is simplicity: upload a file in a browser, run a task such as converting, compressing, merging, or splitting, and download the result without installing dedicated desktop software. That narrow, task-first focus is a big part of why the product spread quickly through word of mouth and search traffic in its early years.$q$, $q$Over time the product expanded into e-signatures, PDF editing, form filling, and AI-assisted features like summarization and translation, alongside native mobile apps for iOS and Android and a desktop application for offline use. The company positions itself as a lightweight alternative to full document-management suites for people who need occasional, fast PDF fixes rather than a complete editing environment. Each new tool has generally been added as its own dedicated page rather than folded into a single complex editor, keeping the learning curve close to zero.$q$, $q$Smallpdf operates on a freemium model: casual users can complete a limited number of tasks per day at no cost, while a Pro subscription unlocks unlimited processing, batch operations, and additional tools for individuals and teams. This structure has made it one of the more widely used PDF utilities globally, particularly among people who land on it through a search for a specific one-off task like 'compress PDF' or 'merge PDF'. Team and Business tiers extend the same underlying tools to organizations that need shared accounts, centralized billing, and administrative oversight.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$who-smallpdf-is-for$q$, $q$Who Smallpdf Is For$q$, 2, ARRAY[$q$Smallpdf suits individuals, students, and small business users who occasionally need to manipulate PDFs and want a fast, no-install solution. Someone converting a scanned form to Word, shrinking a file to email it, or collecting an e-signature on a contract can typically finish the job in a couple of minutes without learning a new application or reading documentation first.$q$, $q$It also works well for small teams that need lightweight document workflows, such as HR or sales staff who regularly send contracts for signature or compress large attachments before sending them to clients, since the Team and Business tiers add shared access, centralized billing, and basic administrative controls without requiring a heavier enterprise document platform.$q$, $q$Freelancers and remote workers who move between devices benefit from Smallpdf's combination of web, mobile, and desktop access, since a file started on a phone can be finished on a laptop without extra setup, and the free tier is often enough for people whose PDF needs are occasional rather than constant. Non-technical users in particular tend to appreciate that no configuration or format knowledge is required to get a usable result.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Heavy daily users of PDF tools will quickly hit the free plan's daily task limits and file-size restrictions, making the tool frustrating without a paid subscription; organizations with high processing volume should budget for Pro or Team pricing from the start rather than relying on the free tier and running into interruptions mid-project.$q$, $q$Smallpdf is not designed for advanced PDF authoring or complex document assembly the way a full desktop suite like Adobe Acrobat Pro is; users who need deep redlining, advanced form logic, extensive Bates numbering, or print-production-grade PDF/X compliance will likely find it too limited for regulated or high-precision publishing workflows.$q$, $q$Enterprises with strict data-residency, on-premise, or air-gapped requirements should evaluate Smallpdf's cloud-processing model carefully, since files are generally uploaded to Smallpdf's servers for conversion; teams that require documents to never leave a private network, or that operate under specific regulatory constraints on where data may be processed, will need a different, self-hosted solution instead.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The platform's foundation is its file-conversion and manipulation toolkit: compressing, merging, splitting, converting to and from Word, Excel, PowerPoint, and JPG, rotating pages, and removing or reordering pages, all handled through simple drag-and-drop web tools that require no prior setup or account creation for many common tasks.$q$, $q$Beyond basic conversions, Smallpdf offers PDF editing for adding text and annotations, an e-signature tool for requesting and applying signatures, form filling, password protection and unlocking, and AI-assisted features such as document summarization and translation that extend the product past pure file conversion into lightweight document review and collaboration.$q$, $q$Access extends across a web app, iOS and Android mobile apps, and a desktop application for offline processing, with Pro and Team plans adding batch processing across many files at once, connected cloud-storage integrations with services such as Google Drive and Dropbox, and administrative controls for shared accounts and centralized billing.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', $q$the-smallpdf-experience$q$, $q$The Smallpdf Experience$q$, 2, ARRAY[$q$New users typically arrive from a search engine looking for one specific task, and Smallpdf's interface is built around that expectation: each tool has its own clean, single-purpose page with a large upload area and minimal configuration, so a first-time visitor can complete a task without creating an account or reading any instructions.$q$, $q$Processing speed is generally fast for typical office documents, and the interface has stayed consistent as the toolkit has grown, so users who learn one tool can usually navigate others without much friction; the multilingual interface also makes it accessible to a broad international audience spanning Europe, the Americas, and parts of Asia.$q$, $q$Friction tends to show up around the free plan's daily limits and occasional upsell prompts nudging users toward Pro, along with the need to reconnect to the internet for browser-based tasks; users who upgrade generally report a smoother, ad-free experience with batch tools, offline desktop access, and fewer interruptions when working through multiple documents in a row.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
