INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ba837227-8967-47be-bd65-e9a86eafe9e3', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Grid/Sheet View$q$, $q$A familiar spreadsheet-like grid with rich formulas, conditional formatting, and unlimited sheets for structuring any kind of work.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Gantt and Timeline View$q$, $q$Visualize project schedules, dependencies, and baselines alongside card, calendar, and grid views of the same data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Workflow Automation$q$, $q$Build no-code automated alerts, approval requests, and record updates that fire based on conditions set on a sheet.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Forms$q$, $q$Collect structured data from internal or external contributors and route submissions directly into a sheet.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Dashboards and Reports$q$, $q$Roll up data from multiple sheets into real-time dashboards and cross-sheet reports for stakeholders and leadership.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Resource and Workload Management$q$, $q$Track team capacity, allocation, and utilization across concurrent projects on Business tier and above.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Control Center Governance$q$, $q$Centrally provision, standardize, and audit projects, templates, and permissions across a large organization.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$AI-Assisted Tools$q$, $q$Smart Assist, formula generation, and text or data analysis features that speed up sheet building and insight generation.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Integrations and API$q$, $q$Native connections to Microsoft 365, Google Workspace, Slack, Jira, Salesforce, Tableau, and Power BI, plus a developer API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Proofing and Approvals$q$, $q$Review and approve creative assets, documents, or process steps directly within an automated workflow.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Highly flexible spreadsheet-based structure that most teams and Excel users can pick up quickly.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Powerful no-code automation engine reduces manual status updates, approvals, and reminders.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Deep enterprise governance, including Control Center and SSO, supports large, standardized rollouts.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Broad integration ecosystem connects Smartsheet to the other tools already in use across a business.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Multiple project views, including Gantt, card, and calendar, let different teams work their preferred way on one shared dataset.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Costs rise quickly once organizations move past the Pro tier into Business, Enterprise, or Advanced Work Management add-ons.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$The grid-first interface can feel denser and less visually modern than newer, design-led work management tools.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Advanced automation, resource management, and reporting features are locked behind higher-priced plans.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$The free plan is no longer offered to new signups, so long-term evaluation now requires a paid subscription or trial.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Mastering complex formulas, cross-sheet references, and automation logic takes real ramp-up time for non-technical users.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Does Smartsheet still offer a free plan?$q$, $q$Smartsheet stopped offering its free plan to new users in August 2024. New customers can start with a free trial before choosing a paid Pro, Business, Enterprise, or Advanced Work Management plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$What's the difference between Smartsheet and a spreadsheet like Excel or Google Sheets?$q$, $q$Smartsheet keeps the familiar grid but adds built-in project views such as Gantt, calendar, and card, along with automation, forms, dashboards, and permissions designed for team-wide work management rather than static data storage.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Does Smartsheet include Gantt charts and timeline tracking?$q$, $q$Yes, Gantt and timeline views with dependencies, baselines, and critical-path highlighting are available starting on the Pro plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Can Smartsheet integrate with other business tools?$q$, $q$Smartsheet natively integrates with tools such as Microsoft 365, Google Workspace, Slack, Jira, Salesforce, Tableau, and Power BI, and exposes a REST API plus the Bridge connector for custom workflows.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Is Smartsheet suitable for large enterprises?$q$, $q$Yes, its Enterprise and Advanced Work Management tiers add SSO, directory integrations, Control Center governance, and premium support built for large, multi-department rollouts.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Project and Portfolio Tracking$q$, $q$Plan schedules, track dependencies with Gantt charts, and roll multiple projects into portfolio-level dashboards for leadership.$q$, $q$Project managers and PMOs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Marketing Campaign and Content Calendars$q$, $q$Coordinate campaign deliverables, approvals, and deadlines across internal teams and external contributors in one shared workspace.$q$, $q$Marketing and creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$IT and Operations Workflow Automation$q$, $q$Automate intake forms, approval chains, and status reminders for recurring operational and IT processes without custom code.$q$, $q$IT and operations teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Resource and Timeline Management$q$, $q$Track schedules, resource allocation, and workload across overlapping projects for teams managing complex, multi-phase work.$q$, $q$Construction and professional services firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Pro$q$, $q$$9/user/month$q$, $q$Annual (monthly billing available at $12/user/month)$q$, $q$["Grid, Gantt, card, and calendar views","Unlimited sheets, forms, and reports","250 automations per month","20 GB attachment storage","Up to 10 editors with unlimited free viewers"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Business$q$, $q$$19/user/month$q$, $q$Annual (monthly billing available at $24/user/month)$q$, $q$["Everything in Pro","Unlimited automations","Timeline view and workload tracking","1 TB attachment storage","API access and custom branding","Minimum of 3 paid members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom annual contract$q$, $q$["Everything in Business","SAML-based SSO","Control Center governance and provisioning","Scenario planning and portfolios","Directory integrations","Unlimited attachment storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$Advanced Work Management$q$, $q$Custom pricing$q$, $q$Custom annual contract$q$, $q$["Everything in Enterprise","Dynamic View and Data Shuttle","Calendar App and Pivot App","Bridge workflow automation","Premium support with expedited response commitments"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Smartsheet is a cloud-based work management and automation platform built around a spreadsheet-style grid layered with dedicated project views, workflow automation, and enterprise reporting tools. Founded in 2005 and headquartered in Bellevue, Washington, the company grew from a simple online spreadsheet into a broad platform used for project tracking, process automation, and portfolio-level reporting across marketing, IT, operations, and construction teams. In January 2025, Smartsheet was taken private by Blackstone and Vista Equity Partners after previously trading on the public markets as SMAR. The platform now spans thousands of organizations, ranging from small teams tracking a handful of projects to large enterprises coordinating programs across many departments and regions.$q$, $q$At its core, Smartsheet pairs a familiar grid interface with Gantt, card, calendar, and board views, so the same underlying dataset can be viewed however a team prefers without duplicating data entry. A no-code automation engine handles alerts, approvals, and reminders, while forms, dashboards, and cross-sheet reports consolidate scattered information into a single source of truth for stakeholders and leadership.$q$, $q$Compared with more visually driven work management tools such as Asana or monday.com, Smartsheet leans into its spreadsheet heritage, favoring data density, formulas, and configurability over a simplified consumer-style interface. That positioning appeals most to operations-heavy teams already comfortable in Excel who need more structure, automation, and governance than a plain spreadsheet or a lightweight task app can provide on its own.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$who-smartsheet-is-for$q$, $q$Who Smartsheet Is For$q$, 2, ARRAY[$q$Smartsheet suits project managers and PMOs who run multiple concurrent projects and need Gantt charts, dependencies, baselines, and resource views to keep schedules and workloads visible in one place. Its reporting and dashboard tools make it easy to summarize status across dozens of projects for leadership without rebuilding spreadsheets by hand every week, which is a common pain point for teams still managing programs in disconnected files. Resource and workload views add visibility into who is over- or under-allocated across simultaneous initiatives.$q$, $q$It also fits operations, IT, and business teams that want to automate recurring processes, such as intake forms, approval chains, and status update reminders, without writing custom code. Marketing and creative teams commonly use it for campaign and content calendars, tracking deliverables, approvals, and deadlines across many internal and external contributors in a single shared workspace.$q$, $q$Larger enterprises migrating off ad hoc spreadsheets benefit most from Smartsheet's governance layer, including SAML-based SSO, admin controls, Control Center provisioning, and audit visibility, which let IT standardize how sheets, templates, and permissions are used company-wide as the organization scales its adoption of the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo users, freelancers, or very small teams who just need a simple task list may find Smartsheet more capability than they need. Its free plan is no longer offered to new signups, so anyone wanting a genuinely no-cost tool for lightweight personal use is better served by simpler list, note, or kanban apps rather than a full work management platform.$q$, $q$Teams that prioritize a clean, visually minimal interface over data density may find the grid-centric layout dense or dated compared with design-forward tools, especially casual users who dislike working inside rows, columns, and formulas to get basic tracking done rather than a more visual card-based workspace.$q$, $q$Budget-conscious small businesses should also weigh costs carefully: the Business plan requires a minimum of three paid members, and the deeper automation, resource management, and API features many teams eventually want are gated behind higher-priced Enterprise or Advanced Work Management tiers, which are quoted through a sales conversation rather than listed publicly.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the foundation, Smartsheet sheets behave like spreadsheets with rich formulas, conditional formatting, and unlimited rows, but each sheet can also be viewed as a Gantt chart, calendar, or card board, so scheduling, task-list, and kanban-style views all stay in sync with the same underlying rows and columns. Column types, cell linking, and cross-sheet formulas let teams model dependencies between related sheets without exporting data elsewhere.$q$, $q$Workflow automation lets teams trigger alerts, approval requests, and record updates based on conditions set on a sheet, while web forms capture structured input from internal or external contributors and route it straight into a sheet. The Bridge connector extends automation across sheets and third-party systems for more complex, multi-step processes.$q$, $q$Dashboards and cross-sheet reports summarize data from many sheets for stakeholders, resource and workload views track team capacity across overlapping projects, and AI-assisted tools such as Smart Assist and formula generation speed up sheet building and analysis. Native integrations with Microsoft 365, Google Workspace, Slack, Jira, Salesforce, Tableau, and Power BI, plus a REST API, connect Smartsheet to the rest of a team's existing toolkit.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', $q$the-smartsheet-experience$q$, $q$The Smartsheet Experience$q$, 2, ARRAY[$q$For anyone comfortable in Excel or Google Sheets, Smartsheet's grid feels immediately familiar, and a large template gallery helps new users set up project trackers, calendars, or intake processes without starting from a blank sheet. iOS and Android apps extend access to updates, comments, and approvals while away from a desktop, and most standard actions carry over cleanly between the web app and mobile devices.$q$, $q$Day to day, collaboration happens in real time through comments, attachments, and proofing tools, while automated reminders and approval requests keep work moving without constant manual follow-up from a project manager. Dashboards give managers and executives a live view of status without needing direct access to the underlying sheets themselves.$q$, $q$Smartsheet backs the product with a documentation-rich help center, an active user community, and tiered support that includes a premium option with faster response commitments on higher plans. Overall, the experience rewards structured, process-driven teams more than users looking for a lightweight, minimal-setup tool for casual personal task tracking.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
