INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2713c5df-5f0a-4c25-8922-9c315b9b040b', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Automatic Time Tracking$q$, $q$Passively captures billable time as staff work in documents, emails, and calls, reducing manual timer entry and time reconstruction at day's end.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Document Automation$q$, $q$Generates court forms, letters, and contracts from practice-area templates populated automatically with matter and contact data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Matter Management$q$, $q$Centralizes documents, emails, tasks, and calendar events for each case so the whole team has a shared, up-to-date view of a matter.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Trust and Billing Accounting$q$, $q$Supports state bar trust-accounting compliance, invoicing, and online payment collection integrated with the firm's matters.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Client Portal$q$, $q$Gives clients a secure place to view case updates, share documents, and communicate with the firm outside of email.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Microsoft 365 Integration$q$, $q$Works closely with Outlook, Word, and other Microsoft 365 tools so time entries and documents sync back into the matter automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$eSignature and eFiling$q$, $q$Allows documents to be signed electronically and filed with supported courts directly from within the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Firm Reporting and Analytics$q$, $q$Provides dashboards on firm profitability, staff activity, and lead conversion for firms on higher-tier plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Archie AI Assistant$q$, $q$An add-on AI assistant designed to help with communication and administrative tasks inside the platform.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Mobile Apps$q$, $q$iOS and Android apps let attorneys view matter details, log time, and manage tasks while away from their desks or in court.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Automatic, passive time capture reduces manual timekeeping and lost billable hours$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Deep document automation with practice-area-specific templates$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Tight integration with Microsoft 365 keeps work in familiar tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Built-in trust accounting supports state bar compliance requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Hands-on onboarding helps firms migrate data from prior systems$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Pricing is not published upfront and requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Contracts are typically structured around annual or multi-year terms rather than simple monthly billing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Deep customization and third-party integrations are more limited than some enterprise-focused competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Learning curve for staff moving from simpler, manual billing and document systems$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Best-fit templates and workflows are concentrated in a handful of practice areas, less tailored for niche practices$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$What is Smokeball used for?$q$, $q$Smokeball is legal practice management software used by law firms to automatically track billable time, automate document creation, manage matters, and handle billing and trust accounting.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$How much does Smokeball cost?$q$, $q$Smokeball advertises plans starting from $149 per user per month, but final pricing is provided as a custom quote based on firm size, selected plan, and add-ons, typically under an annual or 36-month contract.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Does Smokeball offer a free trial?$q$, $q$Smokeball offers a free trial for its Boost plan, allowing firms to evaluate core features before committing to a contract.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$What practice areas does Smokeball support?$q$, $q$Smokeball provides templates and workflows for practice areas including family law, personal injury, estate planning, criminal defense, and real estate, among others.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Is Smokeball available on mobile devices?$q$, $q$Yes, Smokeball offers iOS and Android apps that let attorneys view matter details, log time, and manage tasks while away from the office.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Solo Practitioner Time and Billing$q$, $q$A solo attorney uses automatic time tracking and billing to reduce hours spent on administrative work and ensure billable time is captured accurately.$q$, $q$Solo practitioners and startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Family Law Document Automation$q$, $q$A family law practice uses practice-area templates to quickly generate filings and client documents for divorce, custody, and support matters.$q$, $q$Family law firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Personal Injury Matter Management$q$, $q$A personal injury firm centralizes case documents, medical records, and communications in one matter file to track cases through settlement or trial.$q$, $q$Personal injury firms$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Growing Firm Reporting and Oversight$q$, $q$A multi-attorney firm uses firm-wide reporting on profitability and staff activity to manage growth and identify bottlenecks across matters.$q$, $q$Small to mid-size growing law firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Bill$q$, $q$Custom quote (advertised from $149/user/month)$q$, $q$Annual or 36-month contract$q$, $q$["Invoicing","Time and expense tracking","Online payments","Trust accounting and reporting","Accounting integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Boost$q$, $q$Custom quote$q$, $q$Annual or 36-month contract$q$, $q$["Everything in Bill","Client and matter management","Task and calendar management","Microsoft 365 integration","Client portal","eSignature and eFiling"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Grow$q$, $q$Custom quote$q$, $q$Annual or 36-month contract$q$, $q$["Everything in Boost","Practice area templates","Advanced document automation","Email management","Web app access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$Prosper+$q$, $q$Custom quote$q$, $q$Annual or 36-month contract$q$, $q$["Everything in Grow","Firm insights and profitability reporting","Lead and matter intake management","Custom workflows","Staff activity reporting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Smokeball is a legal practice management platform built specifically for small and mid-sized law firms. Founded in 2011, the company set out to solve a problem familiar to every practicing attorney: the hours lost to manual timekeeping and repetitive document drafting. Rather than building generic case-management software, Smokeball focused on capturing billable time automatically in the background and turning routine paperwork into reusable templates, positioning itself as an efficiency tool first and a record-keeping system second.$q$, $q$The product has evolved considerably since its early days as a Windows desktop application that quietly tracked attorney activity on a computer. Smokeball now offers a fully browser-based experience across its Boost, Grow, and Prosper+ tiers, alongside add-ons such as an AI assistant called Archie, automated intake, and workflow automation. This shift reflects a broader push to meet firms wherever they work, whether that is a shared office, a courtroom, or a home office.$q$, $q$Smokeball serves thousands of law firms, with the bulk of its customer base concentrated in the United States, Australia, and the United Kingdom. Its primary commercial office is in Chicago, Illinois, and the company maintains an ongoing relationship with the American Bar Association and various state bar associations through compliance-oriented features like trust accounting. It competes with other practice-management vendors such as Clio and MyCase, differentiating primarily on its time-capture technology and document automation depth.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$who-smokeball-is-for$q$, $q$Who Smokeball Is For$q$, 2, ARRAY[$q$Smokeball is designed for solo practitioners and small law firms, typically in the range of one to a few dozen attorneys, who need an all-in-one system for time tracking, billing, and document management without hiring dedicated IT staff. Firms that are still relying on a patchwork of spreadsheets, generic word processors, and separate billing software are the clearest fit, since Smokeball consolidates those workflows into a single subscription.$q$, $q$The platform leans heavily on prebuilt templates and workflows for specific practice areas, including family law, personal injury, estate planning, criminal defense, and real estate. Firms practicing in one or two of these core areas tend to get the most value, because Smokeball's document automation and matter checklists are tuned to the paperwork those practices generate most often. Firms with a narrower or more idiosyncratic practice area may need to build more of their own templates from scratch.$q$, $q$It also suits firms that want to reduce the administrative burden on billing attorneys and paralegals. Because time entries are captured automatically as staff work in documents, email, and calls, non-technical staff who dislike manual timers or end-of-day time reconstruction tend to adapt to Smokeball quickly, provided they are comfortable working primarily inside a Microsoft-centric environment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large firms with many offices, complex conflict-checking needs, or heavy custom-integration requirements may find Smokeball more limited than enterprise-grade legal software built for that scale. Firms that need extensive API access, deep third-party integrations beyond Microsoft 365 and common accounting tools, or highly bespoke matter workflows should evaluate whether Smokeball's configuration options go far enough before committing.$q$, $q$Firms that prefer transparent, self-serve, month-to-month pricing are also likely to be frustrated. Smokeball generally requires speaking with sales to get a firm quote, and contracts are typically structured around annual or multi-year terms rather than simple monthly billing, which can be a mismatch for firms wanting to try software with minimal commitment.$q$, $q$Finally, firms operating outside the jurisdictions Smokeball actively supports, or those running a business that is not a licensed legal practice, are not a good fit; the product's trust accounting, bar-compliance features, and legal-specific templates add little value outside of a law-firm context and would represent unnecessary complexity compared with general-purpose project or billing software.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the core of Smokeball is automatic time tracking, which passively records billable minutes as staff work in documents, emails, and phone calls, reducing reliance on manual timers. This is paired with document automation, where firms can generate court forms, letters, and contracts from templates populated with matter data, cutting down on repetitive drafting.$q$, $q$Matter management centralizes communications, documents, tasks, and calendar entries for each case in one place, giving everyone on a matter a shared view of its status. Billing and trust accounting features are built to help firms stay compliant with state bar trust-accounting rules, and they connect to accounting tools and online payment processing so invoices can be issued and collected without leaving the platform. A client portal, eSignature, and eFiling round out the client- and court-facing side of the product.$q$, $q$Higher tiers add reporting and analytics such as firm-wide profitability and staff-activity dashboards, lead and intake management for prospective clients, and custom workflow automation for repeatable processes. Smokeball also offers an AI assistant, Archie, along with add-ons like AutoTime and FamilyPro, extending the core platform for firms that want deeper automation in specific practice areas.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41637f09-c19d-4491-9683-03950483e648', $q$the-smokeball-experience$q$, $q$The Smokeball Experience$q$, 2, ARRAY[$q$New customers typically go through a guided onboarding process, including assistance migrating existing matters, contacts, and documents from a firm's previous system. Smokeball positions this hands-on onboarding as a way to offset the learning curve that comes with adopting a new practice-management system firm-wide.$q$, $q$Because the platform is built around Microsoft 365, day-to-day use tends to feel familiar to firms already working in Outlook and Word, with time entries and documents syncing back into the matter automatically. Mobile apps for iOS and Android extend core functions like viewing matter details, logging time, and checking a daily task digest to attorneys working outside the office or appearing in court.$q$, $q$User feedback generally highlights the automatic time capture and document automation as the most valuable day-to-day benefits, since they reduce administrative overhead for billing attorneys. Common considerations raised by reviewers include the multi-year contract structure, the need to request custom pricing rather than seeing costs upfront, and an adjustment period for staff moving from simpler, more manual systems.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41637f09-c19d-4491-9683-03950483e648', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
