INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('548f9382-785a-42f4-972b-c64402b145c7', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Content Categories$q$, $q$Organize posts into recurring folders (e.g., promotional, curated, evergreen) that SocialBee cycles through automatically to keep the posting calendar varied.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$AI Post Generator$q$, $q$Turn a short prompt into ready-to-edit captions, hashtag suggestions, and tone variations tailored per social network.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Visual Content Creation$q$, $q$Built-in Canva editor plus Unsplash and GIPHY search for sourcing and designing graphics without leaving the platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Content Curation$q$, $q$RSS and URL-based sources let users pull in relevant articles and auto-populate categories with third-party content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Multi-Network Publishing$q$, $q$Schedule and customize posts for Facebook, Instagram, LinkedIn, X, Pinterest, TikTok, YouTube, and Google Business Profile from one calendar.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Analytics and Reporting$q$, $q$Track post and profile performance with historical data, up to two years on higher-tier plans, and exportable branded reports.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Collaboration Tools$q$, $q$Post approval workflows, internal notes, and multi-user access for teams reviewing content before it goes live.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Workspaces$q$, $q$Separate client or brand accounts into distinct workspaces, aimed at agencies managing multiple clients.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Bulk Editing and CSV Import$q$, $q$Upload and edit large batches of posts at once for faster content-calendar setup.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Hashtag Organizer$q$, $q$Save and reuse curated hashtag groups to speed up caption writing across posts.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Content categorization automates a varied, recurring posting schedule instead of one-off manual scheduling.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$AI Post Generator and Copilot assistant speed up caption, hashtag, and visual creation.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Built-in Canva integration and stock image/GIF search remove the need for separate design tools.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Agency-friendly plans with multiple workspaces, branded reporting, and post approval workflows.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$14-day free trial with no credit card required, plus a 30-day money-back guarantee.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$No permanently free plan; a paid subscription is required after the trial period.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Product interface is only available in English, which may limit teams that prefer a localized UI.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$AI-generated captions often need manual editing to match a brand's specific voice.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Entry-level Bootstrap plan limits accounts to a single user, which can be restrictive for small teams.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$No public API, which limits custom automation compared with some competitors.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Does SocialBee offer a free plan?$q$, $q$No. SocialBee runs on paid subscription tiers, but it offers a 14-day free trial that does not require a credit card, plus a 30-day money-back guarantee.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Which social networks does SocialBee support?$q$, $q$SocialBee supports scheduling and publishing to Facebook, Instagram, LinkedIn, X, Pinterest, TikTok, YouTube, and Google Business Profile.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$What is content categorization in SocialBee?$q$, $q$It's a system for grouping posts into folders such as promotional, curated, or evergreen content, then setting a posting cadence for each category so the calendar automatically stays varied.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Can SocialBee generate posts with AI?$q$, $q$Yes. Its AI Post Generator and Copilot assistant can create captions, hashtag suggestions, and network-specific variations from a short prompt.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Is SocialBee suitable for agencies?$q$, $q$Yes. Higher-tier and dedicated agency plans support multiple workspaces, more connected profiles, branded report exports, and multi-user access for managing several clients from one account.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Solo Business Owner Content Consistency$q$, $q$A solopreneur uses content categories to keep a mix of tips, promotions, and curated articles posting automatically across two or three profiles without daily manual scheduling.$q$, $q$Solopreneurs and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Agency Multi-Client Management$q$, $q$A social media agency sets up separate workspaces for each client, using bulk editing and branded reports to manage dozens of profiles and share results with clients.$q$, $q$Social media agencies and freelance managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Marketing Team Content Approval$q$, $q$An in-house marketing team drafts posts collaboratively, routes them through SocialBee's approval workflow, and adds internal notes before anything is published.$q$, $q$Marketing teams and internal communications staff$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Rapid AI-Assisted Content Creation$q$, $q$A busy marketer uses the AI Post Generator to turn a single topic prompt into multiple caption variations and hashtag sets for different networks in minutes.$q$, $q$Content creators and marketers short on time$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Bootstrap$q$, $q$$29/month$q$, $q$Monthly (also available annually at $24.20/month)$q$, $q$["5 social profiles","1 user","10 content categories","10 content sources","Unlimited AI post generation","3 months of analytics history"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Accelerate$q$, $q$$49/month$q$, $q$Monthly (also available annually at $40.83/month)$q$, $q$["10 social profiles","1 user","50 content categories","30 content sources","Advanced analytics with 2 years of history","Hashtag organizer, bulk editor, and CSV uploads","Post approval workflow"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Pro$q$, $q$$99/month$q$, $q$Monthly (also available annually at $82.50/month)$q$, $q$["25 social profiles","3 users","Unlimited categories and sources","5 workspaces","Advanced analytics with branded report exports","Internal notes and post approval"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$Pro50 (Agency)$q$, $q$$179/month$q$, $q$Monthly (also available annually at $149.33/month)$q$, $q$["50 social profiles","5 users","10 workspaces","All Pro plan features at agency scale"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SocialBee is an AI-assisted social media management platform founded in 2016 by Ovi Negrean and Vlad Hosu in Cluj-Napoca, Romania. It was built to give individuals, small businesses, and marketing agencies a single workspace for planning, creating, scheduling, and analyzing content across major networks, including Facebook, Instagram, LinkedIn, X, Pinterest, TikTok, YouTube, and Google Business Profile. The company has grown from an early scheduling tool into a broader content operations platform used by solo creators and larger teams alike, and in 2024 it became part of WebPros, a web-hosting and infrastructure company, while continuing to operate as a distinct product out of Romania.$q$, $q$The platform's defining idea is content categorization. Rather than scheduling every post one by one, users organize content into folders, such as evergreen tips, promotions, or curated articles, and set a recurring posting cadence for each category. SocialBee then fills the calendar automatically, cycling through categories so feeds stay varied instead of repeating the same type of content back to back. This category system is what most reviewers describe as the tool's signature workflow, distinguishing it from simpler queue-based schedulers that simply publish posts in the order they were added, without any concept of topic balance.$q$, $q$Beyond scheduling, SocialBee layers on AI tools: an AI Post Generator and a Copilot assistant turn a short prompt into captions, hashtag ideas, tone variations, and network-specific adaptations of the same message. Built-in Canva integration, stock photo and GIF search, and analytics reporting round out the toolkit, letting teams design, publish, and measure performance without switching between separate apps for content creation, visuals, and reporting, which is a common pain point for smaller teams juggling multiple standalone tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$who-socialbee-is-for$q$, $q$Who SocialBee Is For$q$, 2, ARRAY[$q$Solopreneurs, coaches, consultants, and small business owners who need a steady, varied stream of content across a handful of profiles, but do not have the time or budget for a dedicated social media manager, are a strong fit for SocialBee's category-based automation, since it keeps a calendar filled without requiring daily manual scheduling decisions, freeing up time for the actual work of running a small business or client roster.$q$, $q$Growing marketing teams also get real value from the platform, thanks to bulk editing, CSV imports, a hashtag organizer, and post-approval workflows that let multiple contributors draft, review, and sign off on content before anything goes live on a brand's connected profiles, which is especially useful once more than one person is responsible for what a company posts publicly.$q$, $q$Agencies and freelance social media managers running several client accounts are another core audience. Multi-workspace support, branded report exports, and dedicated agency-tier plans that scale up to 150 connected profiles make it practical to manage many clients from a single SocialBee account without juggling separate logins or tools, while keeping each client's content, categories, and reports isolated from the others.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises that need deep, real-time social listening, sentiment analysis, or advanced social CRM capabilities may find SocialBee's toolset too scheduling-centric, since its strengths sit in planning, categorizing, and publishing content rather than in monitoring broader brand conversations or customer service inboxes, so organizations with those specific needs typically pair it with, or choose instead, a dedicated listening platform.$q$, $q$Teams that require a fully localized, non-English product interface should also weigh their options carefully. SocialBee's own dashboard is only offered in English, even though the content scheduled through it can be written and published in any language the user chooses, since SocialBee does not restrict or translate the text of posts themselves.$q$, $q$Anyone who specifically wants an indefinitely free tool will be disappointed as well. SocialBee's model is a 14-day free trial followed by paid subscription tiers, so users who need a permanent no-cost option for the long term should look at alternatives that offer a genuine free plan, though the trial period is generous enough to fully test the category-based workflow before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Content categories anchor the platform: unlimited AI post generation on paid tiers, RSS and URL-based curation sources, and calendar or list views make it straightforward to plan weeks or months of posts across every connected social profile in one place, reducing the need to prepare content separately for each network.$q$, $q$Native Canva integration and built-in stock photo and GIF libraries support on-platform visual creation, while per-network post customization lets the same core idea be adapted to each channel's format, character limits, and audience expectations without duplicating manual work for every additional channel a brand wants to reach.$q$, $q$Analytics dashboards provide historical reporting, up to two years of history on higher tiers, alongside collaboration tools such as internal notes and approval workflows, plus multi-workspace management that agencies rely on to keep separate client accounts cleanly organized and easy to report on individually.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', $q$the-socialbee-experience$q$, $q$The SocialBee Experience$q$, 2, ARRAY[$q$New users are typically guided through a setup wizard that connects social accounts and helps build out initial content categories, which keeps the learning curve manageable even for people who have never used a dedicated scheduling tool before starting out, and support documentation covers most common setup questions in detail.$q$, $q$Reviewers consistently point to the calendar and queue mechanics, along with the AI Post Generator, as standout conveniences, while also noting that AI-generated captions sometimes need light editing to match a specific brand's tone before they are published live, a limitation common to most AI writing assistants.$q$, $q$Overall sentiment across review sites leans positive, with users citing responsive customer support, frequent feature updates, and reliable publishing, tempered by occasional feedback about the adjustment period needed to learn SocialBee's category-based scheduling logic at first, before it becomes a natural part of a team's content routine.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('57763ac9-8244-4ff8-8a06-376f30693d6f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
