INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Advanced Analytics$q$, $q$Tracks post and page performance metrics to inform content and posting strategy.$q$, 7);
