INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Does SocialPilot offer a free plan?$q$, $q$No, SocialPilot does not have a permanent free plan, but it offers a 14-day free trial that does not require a credit card.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Which social networks does SocialPilot support?$q$, $q$SocialPilot supports Facebook, Instagram, TikTok, X, LinkedIn, Threads, Bluesky, YouTube, Pinterest, and Google Business Profile.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Can agencies white-label their reports?$q$, $q$Yes, higher-tier plans include customizable, brandable PDF reports that agencies can share with their clients.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Does SocialPilot include an AI content assistant?$q$, $q$Yes, its AI Pilot feature generates captions, hashtags, and content ideas, with usage limited by a monthly AI-credit allowance per plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Is there a mobile app for SocialPilot?$q$, $q$Yes, SocialPilot offers both iOS and Android apps for scheduling and monitoring accounts on the go.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Agency Client Management$q$, $q$Agencies organize multiple client accounts, route posts through client approval workflows, and export white-label reports.$q$, $q$Marketing agencies and freelance social media managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Small Business Social Scheduling$q$, $q$Small teams schedule and publish content across several networks affordably without dedicated social media staff.$q$, $q$Small business owners and solopreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Multi-Location Brand Consistency$q$, $q$Franchises and multi-location businesses coordinate consistent, on-brand posting schedules across locations.$q$, $q$Multi-location brands and franchises$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Online Reputation and Review Management$q$, $q$Businesses request new customer reviews and monitor or respond to existing reviews from one dashboard.$q$, $q$Local and service-based businesses such as restaurants and healthcare providers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Essentials$q$, $q$$20/month ($17/month billed annually)$q$, $q$Monthly or annual$q$, $q$["5 social media accounts","1 user","500 AI credits","Content library","Basic analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Standard$q$, $q$$40/month ($34/month billed annually)$q$, $q$Monthly or annual$q$, $q$["10 social media accounts","3 users","1,000 AI credits","Bulk scheduling","Social inbox","Team collaboration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Premium$q$, $q$$100/month ($85/month billed annually)$q$, $q$Monthly or annual$q$, $q$["20 social media accounts","6 users","5,000 AI credits","Advanced analytics","Client approval workflow","White-label reports"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$Ultimate$q$, $q$$200/month ($170/month billed annually)$q$, $q$Monthly or annual$q$, $q$["40 social media accounts","Unlimited users","Unlimited AI credits","Dedicated account manager","Migration support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$SocialPilot is a social media management and scheduling platform founded in 2014 that helps teams plan, publish, and analyze content across multiple networks from a single dashboard. It supports Facebook, Instagram, TikTok, X, LinkedIn, Threads, Bluesky, YouTube, Pinterest, and Google Business Profile, giving marketers a consolidated view of their social presence without switching between platforms.$q$, $q$The product bundles a content calendar, bulk scheduling, an AI-assisted writing tool called AI Pilot, a unified inbox, and review management into tiered monthly or annual plans. Integrations with Canva, Zapier, Shopify, WordPress, Dropbox, and Google Drive extend its use as a hub for content sourcing and publishing rather than a standalone scheduler.$q$, $q$SocialPilot is generally positioned as a more affordable alternative to enterprise-grade suites such as Sprout Social or Hootsuite, with pricing that scales by number of connected accounts, users, and AI credits rather than by feature access alone, culminating in a custom-priced Enterprise tier with API access and single sign-on.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$who-socialpilot-is-for$q$, $q$Who SocialPilot Is For$q$, 2, ARRAY[$q$Digital marketing agencies managing several client accounts are a core audience: white-label PDF reports, client approval workflows, and per-client account grouping let agencies run campaigns and demonstrate results without exposing the SocialPilot brand to end clients.$q$, $q$Small businesses and solopreneurs who need to keep a consistent posting cadence across several networks but do not want the cost or complexity of an enterprise suite also fit well, since the entry-level plan covers a handful of accounts and basic analytics at a comparatively low monthly price.$q$, $q$Multi-location businesses and franchises, along with service-driven industries like real estate, healthcare, restaurants, and law firms, use SocialPilot to keep branded content consistent across locations while its review management tools help these customer-facing businesses monitor and respond to online reviews.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Enterprises that need deep social listening, sentiment analysis, or brand-monitoring across the open web will likely find SocialPilot's engagement tools thinner than those of dedicated listening platforms, since its inbox and review tools focus on owned accounts rather than broad web or competitor monitoring.$q$, $q$Anyone expecting a permanently free tool should look elsewhere, as SocialPilot offers only a 14-day trial rather than an ongoing free tier, meaning long-term use always requires a paid subscription regardless of team size.$q$, $q$Teams that depend heavily on native paid-ad management, granular employee advocacy programs, or highly customizable analytics dashboards may find those capabilities more limited than in higher-priced, specialist platforms, making SocialPilot a better fit for organic content workflows than for ad-heavy operations.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Bulk scheduling lets users upload and queue hundreds of posts at once via spreadsheet import, while a visual content calendar and browser extension make it easy to plan campaigns in advance and curate content while browsing the web.$q$, $q$AI Pilot generates captions, hashtag suggestions, and content ideas directly inside the composer, with usage governed by a monthly AI-credit allowance that scales with the chosen plan, so heavier AI use requires a higher tier.$q$, $q$A unified social inbox consolidates comments and messages across connected accounts, client approval workflows allow stakeholders to review posts before they go live, and white-label analytics reports let agencies export branded, customizable PDFs alongside built-in review-request and response automation.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b0973005-06cc-44c0-81b7-f55d44c44d48', $q$the-socialpilot-experience$q$, $q$The SocialPilot Experience$q$, 2, ARRAY[$q$New users are guided through connecting accounts and building an initial posting calendar, and the interface groups clients or brands so agencies can switch context without leaving the dashboard, keeping day-to-day scheduling relatively quick to pick up.$q$, $q$iOS and Android apps extend scheduling and monitoring to mobile devices, and a browser extension supports content curation on the go, while customer support is available through channels such as chat and a help-center knowledge base for troubleshooting.$q$, $q$Overall, the experience is tuned for price-conscious agencies and small teams that want dependable multi-network scheduling, basic AI assistance, and client-facing reporting, rather than the deep listening or advertising tooling found in higher-end enterprise suites.$q$]::text[], 4);
