INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$PDF Editing$q$, $q$Edit existing text and images directly inside a PDF, plus add new text, shapes, stamps, and highlights.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Merge and Split$q$, $q$Combine multiple files into a single PDF or split and rearrange pages within an existing document.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$File Conversion$q$, $q$Convert PDFs to and from Word, Excel, PowerPoint, HTML, and common image formats.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Compression$q$, $q$Reduce the file size of large PDFs while aiming to preserve document quality.$q$, 3);
