INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$E-Signature$q$, $q$Prepare and send documents for digital signature as part of the standard editing workflow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Security and Redaction$q$, $q$Apply password protection, set permission restrictions, and redact sensitive content from documents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Form Creation and Filling$q$, $q$Build fillable PDF forms and complete existing forms directly within the editor.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$AI Document Tools$q$, $q$Use AI-assisted chat, translation, and summarization features to interact with and process document content.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Cloud Storage Integration$q$, $q$Connect to Dropbox, Google Drive, SharePoint, and Evernote to open and save files across devices.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Combines desktop and web access under a single subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Broad feature set covering editing, conversion, security, and e-signature in one product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Free web-based tools available for basic, occasional PDF tasks$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$OCR and batch processing useful for offices handling scanned paperwork$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Mobile apps and cloud storage integrations support working across devices$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$No native macOS desktop application, only browser-based access for Mac users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Full feature set, including OCR and AI tools, requires a paid subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Free web tools carry usage limits that push regular users toward paid plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Positioned more toward individuals and SMBs than large enterprise document workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Multiple subscription tiers can make it less obvious which plan matches actual needs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Is Soda PDF free to use?$q$, $q$Soda PDF offers free web-based tools for basic tasks like conversion and simple edits, but these have usage limits. The full editing, OCR, and AI feature set requires a paid Standard, Pro, or Business subscription, and a free trial is available to test the paid tiers.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Does Soda PDF have a Mac app?$q$, $q$Soda PDF does not offer a native macOS desktop application. Mac users are directed to use the browser-based web app instead, which runs on any device with a modern browser.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$What platforms does Soda PDF support?$q$, $q$Soda PDF runs as a Windows desktop application and as a web app accessible from any browser, with mobile apps for Android and iOS providing additional on-the-go access.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Can Soda PDF convert scanned documents into editable text?$q$, $q$Yes. Soda PDF includes OCR (optical character recognition) on its Pro and higher plans, which scans and recognizes text within scanned documents or images so it can be searched and edited.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Who owns Soda PDF?$q$, $q$Soda PDF is developed by LULU Software, a Montreal-based company founded in 2010 that was acquired in 2018 by Avanquest, the software division of the Claranova group.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Everyday PDF editing for individuals$q$, $q$Edit text, add annotations, and make quick corrections to PDF files without needing a full office suite.$q$, $q$Freelancers and individual users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Document conversion and file cleanup$q$, $q$Convert PDFs to and from Word, Excel, and PowerPoint, merge multiple files, and compress oversized documents.$q$, $q$Administrative and office staff$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Contract review and e-signature$q$, $q$Prepare, redact, and send contracts and agreements for digital signature within a single workflow.$q$, $q$Small business owners and legal/HR teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Digitizing scanned paperwork$q$, $q$Use OCR and batch processing to turn scanned paper documents into searchable, editable digital files.$q$, $q$Teams handling high volumes of paper-based records$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Standard$q$, $q$$6.75/user/month$q$, $q$Billed annually$q$, $q$["PDF text and image editing","Form filling","File conversion","Web and desktop access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Pro$q$, $q$$8.25/user/month$q$, $q$Billed annually$q$, $q$["Everything in Standard","OCR for scanned documents","Document comparison","Redaction","E-signature","AI tools access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$Business$q$, $q$$16.67/user/month$q$, $q$Billed annually$q$, $q$["Everything in Pro","Batch processing","Self-serve plan management","Phone support","Larger cloud storage allowance"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Soda PDF is a PDF editing and conversion platform built by LULU Software, a Montreal-based company founded in 2010 that is now part of the Claranova (Avanquest) group. The product spans a browser-based web app and a downloadable Windows desktop application, both aimed at letting individuals and businesses create, edit, and manage PDF documents without needing separate specialized software for each task, and without switching between unrelated tools for viewing, editing, and converting. The company has grown the product over more than a decade, including through acquisitions of other PDF and conversion tools that were folded into the Soda PDF lineup.$q$, $q$The toolset covers the everyday PDF workflow from start to finish: editing text and images, merging and splitting files, rearranging pages, converting to and from formats like Word, Excel, PowerPoint, HTML, and image files, compressing large documents, adding e-signatures, and protecting files with passwords and redaction. In recent years Soda PDF has layered on AI-assisted features such as document chat, translation, and summarization on top of its traditional editing engine, extending the product beyond pure formatting tasks and closer to a general document-productivity assistant.$q$, $q$Commercially, Soda PDF follows a freemium model rather than charging up front for every capability. A set of free web-based tools handles basic conversions and edits with usage limits, while paid Standard, Pro, and Business subscriptions unlock the full desktop and web editor, OCR, batch processing, larger cloud storage allowances, and AI features. A free trial is available for prospective subscribers who want to test the paid tiers before committing to an annual plan, and pricing scales by the number of licensed users rather than requiring a single all-or-nothing purchase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$who-soda-pdf-is-for$q$, $q$Who Soda PDF Is For$q$, 2, ARRAY[$q$Soda PDF suits individuals and freelancers who need to edit, convert, or sign PDFs occasionally and want a lower-cost alternative to premium desktop suites, especially those who are comfortable working primarily on Windows or in a browser and do not need a dedicated design or publishing tool for the job.$q$, $q$It also fits small and mid-sized businesses that process a steady volume of contracts, forms, and scanned paperwork, since the Pro and Business plans add OCR for scanned text, batch conversion, and e-signature workflows that reduce manual document handling for office, HR, and administrative teams working through repetitive paperwork.$q$, $q$Organizations already standardized on Windows desktops, or teams that want one subscription covering both desktop and web access rather than juggling separate licenses, are a natural match, since Soda PDF's plans are structured around exactly that combined-access model, letting staff move between office and remote work without losing access to the same toolset or having to re-purchase a second license for the browser version.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Mac-centric users and teams are the clearest mismatch: Soda PDF does not offer a native macOS desktop application, directing those users to the browser-based version instead, which limits offline access and the kind of deep OS-level integration that a dedicated Mac app would normally provide.$q$, $q$Teams that need heavyweight, real-time document collaboration, granular enterprise content management, or deep integration with a broader document-management ecosystem may find Soda PDF's feature set more consumer- and SMB-oriented than what large, compliance-heavy enterprise workflows typically require from a document platform, and may prefer a specialized enterprise content-management vendor instead.$q$, $q$Users hoping for a fully free, unlimited PDF editor should also look elsewhere, since Soda PDF's no-cost web tools are capped in usage, and the more advanced editing, OCR, and AI capabilities sit behind a paid subscription rather than being available indefinitely at no cost.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Soda PDF offers text and image editing, annotation, stamping, highlighting, and form creation and filling, letting users modify a PDF's content much like a word processor rather than only viewing and printing it as a static file. Users can also insert, delete, and reorder individual pages within a document without recreating the whole file from scratch.$q$, $q$File organization and conversion round out the everyday toolkit: merging multiple files into one PDF, splitting and rearranging pages, converting PDFs to and from Word, Excel, PowerPoint, HTML, and images, and compressing oversized documents to more manageable file sizes for storage or sharing over email and messaging apps.$q$, $q$On the security and productivity side, Soda PDF adds password protection, permission controls, and redaction, OCR to make scanned documents searchable and editable, integrated e-signature requests for contracts, and newer AI tools for chatting with a document's content, translating it into another language, and generating summaries of long files.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', $q$the-soda-pdf-experience$q$, $q$The Soda PDF Experience$q$, 2, ARRAY[$q$Soda PDF has gone through a visual and structural refresh, pitched by the company as a modernized interface layered over a rebuilt underlying engine, aiming for a cleaner, more approachable layout than older PDF editors while keeping toolbars organized around specific tasks like editing, converting, and securing files rather than one dense, catch-all menu.$q$, $q$Cross-device continuity is a recurring theme in how the product is used: a subscription can cover both the Windows desktop app and the web app, and cloud storage integrations with services like Dropbox, Google Drive, SharePoint, and Evernote let a user start a file on one device and finish it on another, with Android and iOS apps extending that same access to mobile phones and tablets.$q$, $q$New users typically start with the free trial or the limited free web tools before deciding whether to upgrade, and paid business plans add phone support and self-serve plan management on top of the core editor, so the overall experience scales from a casual, one-off conversion task up to an ongoing subscription for teams with recurring, high-volume document work and multiple licensed seats to manage.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
