INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d012baf-f581-41bc-84f4-cdf167ff2fba', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Multiple Data Sources$q$, $q$Connects to Airtable, Google Sheets, or Softr's own built-in database as the backend for any app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Pre-built Blocks and Templates$q$, $q$A library of UI blocks (lists, tables, forms, charts, calendars) and full app templates for portals, marketplaces, and directories.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$User Groups and Permissions$q$, $q$Role-based access control to show or hide pages, records, and fields for different customer or team segments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Workflows and Automations$q$, $q$Point-and-click automations that send emails, update records, and chain multi-step actions without code.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$AI Blocks$q$, $q$Built-in AI features for generating, summarizing, or transforming content directly inside a published app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Payments$q$, $q$Native Stripe integration for accepting one-time payments and recurring subscriptions inside an app.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Custom Code and Domains$q$, $q$Ability to inject custom CSS and JavaScript and connect a custom domain for a fully white-labeled app.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Responsive and PWA Support$q$, $q$Apps are mobile-responsive by default and can be installed as progressive web apps on phones.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Third-Party Integrations$q$, $q$Connects to external tools through Zapier, Make, and native integrations to extend app functionality.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Fast to launch functional web apps without writing code$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Works directly with Airtable and Google Sheets data teams already use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Free plan and free trial let users test the platform before paying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Built-in payments, permissions, and automations reduce the need for extra tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Template library speeds up common build patterns like portals and directories$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Paid plans grow more expensive as app users and data volume increase$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$No native iOS or Android app compilation, only responsive web and PWA output$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Complex custom logic can hit the limits of the block-based builder$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Performance can lag behind a custom-coded application at larger scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Reliance on connected data sources means the underlying source's limits apply$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Does Softr require coding skills?$q$, $q$No. Softr is built as a no-code, drag-and-drop platform, though it offers optional custom code and JavaScript for advanced customization.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$What data sources does Softr support?$q$, $q$Softr can connect to Airtable, Google Sheets, or use its own built-in database as the backend for an app.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Can I accept payments in a Softr app?$q$, $q$Yes. Softr includes a native Stripe integration for one-time payments and recurring subscriptions.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Does Softr offer a free plan?$q$, $q$Yes. Softr has a free plan with limited app users and database records, alongside paid plans that raise those limits.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Can I use a custom domain with a Softr app?$q$, $q$Yes. Custom domain support is available, letting builders publish apps under their own branded domain.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Client Portals$q$, $q$Agencies and service businesses build branded, permissioned portals so clients can view project data, submit requests, or track status.$q$, $q$Agencies and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Internal Tools$q$, $q$Operations, HR, and support teams build directories, trackers, and dashboards on top of existing spreadsheet or Airtable data.$q$, $q$Internal operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Marketplaces and Directories$q$, $q$Founders build two-sided marketplaces or listing directories using Airtable records as the underlying data model.$q$, $q$Startup founders$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Membership and Community Sites$q$, $q$Creators build gated content or community platforms with paid membership tiers powered by the built-in payments feature.$q$, $q$Creators and community builders$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, $q$["10 app users","5,000 database records","500 workflow actions per month","5 AI credits per month","Free custom domain"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Basic$q$, $q$$49/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["20 app users","50,000 database records","2,500 workflow actions per month","10 AI credits per month","Custom code access","Embed apps externally"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Professional$q$, $q$$139/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["100 app users","500,000 database records","10,000 workflow actions per month","50 AI credits per month","Custom user groups"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$Business$q$, $q$$269/month$q$, $q$Monthly (annual billing available at a discount)$q$, $q$["500 app users","1,000,000 database records","25,000 workflow actions per month","100 AI credits per month","Unlimited user groups","SSO available as an add-on"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Softr is a no-code platform founded in 2019 by Mariam Hakobyan and Artur Mkrtchyan and headquartered in Berlin, Germany. It lets non-technical builders turn structured data into fully functional web apps, client portals, marketplaces, and internal tools. Rather than starting from a blank canvas, Softr treats an existing dataset in Airtable, Google Sheets, or its own built-in database as the source of truth, then layers a visual interface, logic, and permissions on top of it.$q$, $q$The platform is organized around pre-built blocks, such as lists, tables, forms, charts, and calendars, along with full application templates covering common use cases like directories, dashboards, and membership sites. Builders assemble pages by dragging blocks onto a canvas, binding them to records, and configuring user groups, workflows, and payment rules through point-and-click settings rather than code, with optional custom CSS and JavaScript available for deeper tweaks.$q$, $q$Softr competes in the broader no-code app-building category alongside tools such as Bubble, Glide, and Stacker, but differentiates itself by leaning heavily on spreadsheet-like data sources that many small businesses already maintain. That positioning has helped it attract solo founders, agencies, and internal ops teams who want to ship a working app quickly without hiring engineers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$who-softr-is-for$q$, $q$Who Softr Is For$q$, 2, ARRAY[$q$Softr suits non-technical founders and solopreneurs who already keep their business data in Airtable or Google Sheets and want a client-facing or internal front end without commissioning custom software. It works well for anyone whose core need is displaying, filtering, and editing records behind a login rather than building a novel algorithm or interaction pattern.$q$, $q$Agencies and consultants are a natural fit too, since Softr's white-label options, custom domains, and user-group permissions make it practical to spin up branded client portals for multiple customers from a shared template, then customize each instance quickly.$q$, $q$Internal operations, HR, and support teams also use Softr to build lightweight internal tools, such as employee directories, approval trackers, or support dashboards, where the priority is getting a usable interface in front of colleagues fast rather than engineering a polished consumer product.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need a highly bespoke user interface, an unconventional interaction design, or business logic that goes well beyond filtering, forms, and simple workflows will likely find the block-based builder confining, since deep customization usually requires injected custom code rather than native support.$q$, $q$Organizations expecting to operate at large scale, with very high record counts, heavy concurrent usage, or complex relational data models, may outgrow the practical limits of spreadsheet-style or hosted data sources and the app-user tiers Softr's plans are priced around, eventually needing a custom-built backend instead.$q$, $q$Anyone who specifically needs native iOS or Android apps distributed through an app store should also look elsewhere, since Softr publishes responsive web apps and progressive web apps rather than compiling native mobile binaries.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Softr connects to Airtable, Google Sheets, or its own built-in database, then exposes that data through building blocks like lists, tables, grids, calendars, and charts, so builders can display and edit records without writing queries.$q$, $q$Access control is handled through user groups and permissions, letting builders restrict pages, records, or fields to specific customer segments, team roles, or paying subscribers, while workflows and automations trigger emails, record updates, and multi-step actions in response to user behavior.$q$, $q$Softr also bundles native Stripe-based payments for one-time charges and subscriptions, AI blocks for generating or summarizing content inside an app, custom code and custom domain support for white-labeling, and integrations with tools like Zapier and Make for connecting external systems.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3c1c11fd-4faf-4d6c-8f2f-a21304ececf9', $q$the-softr-experience$q$, $q$The Softr Experience$q$, 2, ARRAY[$q$Getting started with Softr is generally fast: builders pick a template or start from a data source, and the drag-and-drop editor keeps most decisions visual, which shortens the path from idea to a shareable link compared with hand-coding a front end.$q$, $q$The trade-off shows up as projects grow more ambitious; achieving a fully custom look or intricate logic often means reaching for the custom code panel or a third-party integration, and heavier apps can feel less responsive than a purpose-built application.$q$, $q$Overall, Softr trades some ceiling on customization and performance for a substantially lower floor on time and technical skill required to launch, which is why it tends to earn strong marks from non-technical builders shipping portals and internal tools rather than teams building highly differentiated consumer products.$q$]::text[], 4);
